    private void btnSignInVerificationActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnSignInVerificationActionPerformed
        // TODO add your handling code here:
        BackEnd be = new BackEnd();
        be.loginArray();
        if(be.checkLogin(txtUsername.getText(), pfPassword.getText()) == false ){
            lblSignInError.setText("Username or password incorrect");
        }
        else{
            
            new Game();
            
            dispose(); 
        }
        
    }//GEN-LAST:event_btnSignInVerificationActionPerformed

